fn parse_http_request(request: &str) -> (SmallVec<[(&str, &str); 8]>, HashMap<String, String>, Vec<String>, BTreeMap<String, String>) {
    let mut common_headers = SmallVec::new();
    let mut header_map = HashMap::new();
    let mut raw_headers = Vec::new();
    let mut cookies_map = BTreeMap::new();

    for line in request.lines() {
        if let Some(colon_idx) = line.find(':') {
            let (name, rest) = line.split_at(colon_idx);
            let value = rest[1..].trim();
            raw_headers.push(line.to_string());

            match name.to_lowercase().as_str() {
                "content-type" | "content-length" | "user-agent" | "host" | "accept" | "cookie" => {
                    common_headers.push((name, value));
                }
                _ => {}
            }

            header_map.insert(name.to_string(), value.to_string());

            if name.eq_ignore_ascii_case("cookie") {
                for cookie in value.split(';') {
                    if let Some(eq_idx) = cookie.find('=') {
                        let (cookie_name, cookie_value) = cookie.split_at(eq_idx);
                        cookies_map.insert(cookie_name.trim().to_string(), cookie_value[1..].trim().to_string());
                    }
                }
            }
        }
    }

    (common_headers, header_map, raw_headers, cookies_map)
}
