		return 0, 0, 0, 0, errors.New("input slice is empty")
	}

	sort.Float64s(responseTimes)

	// Calculate mean
	var sum float64
	for _, time := range responseTimes {
		sum += time
	}
	mean := sum / float64(len(responseTimes))

	// Calculate median
	median := responseTimes[len(responseTimes)/2]
	if len(responseTimes)%2 == 0 {
		median = (responseTimes[len(responseTimes)/2-1] + responseTimes[len(responseTimes)/2]) / 2
	}

	// Calculate 95th percentile
	index95 := int(0.95 * float64(len(responseTimes)))
	if index95 >= len(responseTimes) {
		index95 = len(responseTimes) - 1
	}
	percentile95 := responseTimes[index95]

	// Return results
	return mean, median, percentile95, len(responseTimes), nil
