func analyze_temperature_data(temps []float64) (float64, float64) {
	if len(temps) == 0 {
		return 0, 0
	}

	var sum float64
	for _, temp := range temps {
		sum += temp
	}

	mean := sum / float64(len(temps))

	var varianceSum float64
	for _, temp := range temps {
		varianceSum += (temp - mean) * (temp - mean)
	}

