fn build_indexing_pipeline(
    documents: Vec<String>, 
    keywords: HashSet<String>
) -> (
    BTreeMap<String, Vec<usize>>, 
    VecDeque<String>, 
    HashSet<String>, 
    SmallVec<[usize; 8]>, 
