        indexed_documents.insert(doc_id.to_string());
        for (position, word) in document.split_whitespace().enumerate() {
            if keywords.contains(word) {
                keyword_positions.entry(word.to_string())
                    .or_insert_with(Vec::new)
                    .push(position);
