    let mut accounts_for_review = BTreeSet::new();
    let mut last_five_transactions = ArrayVec::new();

    for transaction in transactions.iter() {
        let balance = account_balances.entry(transaction.account_id.clone()).or_insert(0.0);

        match transaction.transaction_type.as_str() {
            "deposit" => {
                *balance += transaction.amount;
                if last_five_transactions.len() == 5 {
                    last_five_transactions.remove(0);
                }
                last_five_transactions.push((transaction.clone(), true));
            },
            "withdrawal" => {
                if *balance >= transaction.amount {
                    *balance -= transaction.amount;
                    if transaction.amount > 10000.0 { // Arbitrarily high amount
                        accounts_for_review.insert(transaction.account_id.clone());
                    }
                    if last_five_transactions.len() == 5 {
                        last_five_transactions.remove(0);
                    }
                    last_five_transactions.push((transaction.clone(), true));
                } else {
                    pending_transactions.push_back(transaction.clone());
                    if last_five_transactions.len() == 5 {
                        last_five_transactions.remove(0);
                    }
                    last_five_transactions.push((transaction.clone(), false));
                }
            },
            _ => {},
        }
    }

    (pending_transactions, account_balances, accounts_for_review, last_five_transactions)
}
