use std::collections::HashSet;
use smallvec::SmallVec;

fn aggregate_sensor_data(data: Vec<(String, f32)>) -> (Vec<f32>, HashSet<String>, SmallVec<[f32; 5]>) {
    let mut sensor_readings = Vec::new();
    let mut unique_sensor_ids = HashSet::new();
    let mut smooth_buffer = SmallVec::<[f32; 5]>::new();

    for (sensor_id, reading) in data {
        sensor_readings.push(reading);
        unique_sensor_ids.insert(sensor_id);
    }

    let len = sensor_readings.len();
    let start = if len >= 5 { len - 5 } else { 0 };
    smooth_buffer.extend_from_slice(&sensor_readings[start..]);

    (sensor_readings, unique_sensor_ids, smooth_buffer)
}
