use std::collections::{HashMap, BTreeSet};
use arrayvec::ArrayVec;

fn update_inventory(
    changes: Vec<(String, i32)>
) -> (HashMap<String, i32>, BTreeSet<String>, ArrayVec<(String, i32), 16>) {
    let mut inventory: HashMap<String, i32> = HashMap::new();
    let mut out_of_stock: BTreeSet<String> = BTreeSet::new();
    let mut incoming_products: ArrayVec<(String, i32), 16> = ArrayVec::new();

    for (product_id, quantity_change) in changes {
        let entry = inventory.entry(product_id.clone()).or_insert(0);
        *entry += quantity_change;

        if *entry <= 0 {
            out_of_stock.insert(product_id.clone());
        } else {
            out_of_stock.remove(&product_id);
        }

        if quantity_change > 0 {
            incoming_products.push((product_id.clone(), quantity_change));
        }
    }

    (inventory, out_of_stock, incoming_products)
}
